// Parse Telegram message and classify command
const body = $input.first().json.body || $input.first().json;

// Extract Telegram update data
const update = body;
const message = update.message || update.edited_message || {};
const callbackQuery = update.callback_query || {};

const chatId = (message.chat && message.chat.id) || 
               (callbackQuery.message && callbackQuery.message.chat && callbackQuery.message.chat.id) ||
               '6190676114';

const text = (message.text || callbackQuery.data || '').trim();
const fromUser = (message.from && message.from.username) || 
                 (callbackQuery.from && callbackQuery.from.username) || 'unknown';

console.log('Telegram message received:', text, 'from:', fromUser);

// Classify message type
let commandType = 'other';
let invoiceId = null;

if (text.toUpperCase().startsWith('ACCEPT_')) {
  commandType = 'accept';
  invoiceId = text.substring(7).trim();
} else if (text.toUpperCase().startsWith('REJECT_')) {
  commandType = 'reject';
  invoiceId = text.substring(7).trim();
} else if (text === '/start') {
  commandType = 'start';
} else if (text === '/status') {
  commandType = 'status';
} else if (text === '/help') {
  commandType = 'help';
}

// Validate invoice ID is numeric
if (invoiceId && !/^\d+$/.test(invoiceId)) {
  commandType = 'invalid';
}

return [{
  json: {
    command_type: commandType,
    invoice_id: invoiceId,
    chat_id: String(chatId),
    text: text,
    from_user: fromUser,
    raw_update: JSON.stringify(body)
  }
}];

