// Handle other commands: /start, /status, /help, or unknown
const cmdData = $input.first().json;
const cmdType = cmdData.command_type;

let replyText = '';

switch(cmdType) {
  case 'start':
    replyText = '👋 Welcome to OpenClaw Invoice Bot!\n\nI process invoices automatically. Commands:\n/status - System status\n/help - Help';
    break;
  case 'status':
    replyText = '🟢 System Status\n\nAll systems operational:\n• Invoice intake: Active\n• OCR: Active\n• Fraud detection: Active\n• Database: Connected';
    break;
  case 'help':
    replyText = '📖 Available Commands:\n\n/start - Welcome\n/status - System status\n/help - This help\n\nTo review invoices:\nACCEPT_{id} - Accept invoice\nREJECT_{id} - Reject as spam';
    break;
  case 'invalid':
    replyText = '⚠️ Invalid invoice ID. Format: ACCEPT_123 or REJECT_123';
    break;
  default:
    replyText = '❓ Unknown command: ' + cmdData.text + '\n\nType /help for commands.';
}

return [{
  json: {
    chat_id: cmdData.chat_id,
    reply_text: replyText
  }
}];
